import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.CTpQozEL.js";const m=JSON.parse('{"title":"실험적 기능","description":"OpenClaw 실험적 기능: 기본값이 아닌 opt-in 프리뷰 서페이스 목록과 권장 사용법","frontmatter":{"title":"실험적 기능","description":"OpenClaw 실험적 기능: 기본값이 아닌 opt-in 프리뷰 서페이스 목록과 권장 사용법"},"headers":[],"relativePath":"concepts/experimental-features.md","filePath":"concepts/experimental-features.md","lastUpdated":null}'),n={name:"concepts/experimental-features.md"};function d(l,e,s,c,i,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="실험적-기능" tabindex="-1">실험적 기능 <a class="header-anchor" href="#실험적-기능" aria-label="Permalink to &quot;실험적 기능&quot;">​</a></h1><p>OpenClaw의 실험적 기능은 <strong>opt-in 프리뷰 서페이스</strong>입니다. 안정적인 기본값이나 장기적인 공개 계약이 될 자격을 갖추기 전에 현실 세계에서 더 많이 검증되어야 하기 때문에 명시적인 플래그 뒤에 둡니다.</p><p>일반 설정과는 다르게 취급하세요:</p><ul><li>관련 문서가 시도를 권하지 않는 한 <strong>기본적으로 끄세요</strong>.</li><li>안정 설정보다 <strong>형태와 동작이 더 빠르게 변경</strong>될 수 있다고 예상하세요.</li><li>안정 경로가 이미 존재하면 그것을 먼저 사용하세요.</li><li>OpenClaw를 광범위하게 배포 중이라면, 공유 기준에 포함하기 전에 더 작은 환경에서 실험 플래그를 테스트하세요.</li></ul><h2 id="현재-문서화된-플래그" tabindex="-1">현재 문서화된 플래그 <a class="header-anchor" href="#현재-문서화된-플래그" aria-label="Permalink to &quot;현재 문서화된 플래그&quot;">​</a></h2><table tabindex="0"><thead><tr><th>서페이스</th><th>키</th><th>언제 사용하는가</th><th>자세히</th></tr></thead><tbody><tr><td>로컬 모델 런타임</td><td><code>agents.defaults.experimental.localModelLean</code></td><td>더 작거나 엄격한 로컬 백엔드가 OpenClaw의 전체 기본 도구 서페이스에서 막힐 때</td><td><a href="/openclaw-docs-ko/gateway/local-models">로컬 모델</a></td></tr><tr><td>메모리 검색</td><td><code>agents.defaults.memorySearch.experimental.sessionMemory</code></td><td><code>memory_search</code>가 이전 세션 기록을 인덱스하길 원하고 추가 저장/인덱싱 비용을 감수할 수 있을 때</td><td><a href="/openclaw-docs-ko/reference/memory-config#session-memory-search-experimental">메모리 설정 참조</a></td></tr><tr><td>구조화된 계획 도구</td><td><code>tools.experimental.planTool</code></td><td>호환되는 런타임과 UI에서 다단계 작업 추적을 위한 구조화된 <code>update_plan</code> 도구를 노출하려 할 때</td><td><a href="/openclaw-docs-ko/gateway/configuration-reference#toolsexperimental">Gateway 설정 참조</a></td></tr></tbody></table><h2 id="로컬-모델-린-lean-모드" tabindex="-1">로컬 모델 린(lean) 모드 <a class="header-anchor" href="#로컬-모델-린-lean-모드" aria-label="Permalink to &quot;로컬 모델 린(lean) 모드&quot;">​</a></h2><p><code>agents.defaults.experimental.localModelLean: true</code>는 성능이 떨어지는 로컬 모델 환경을 위한 압력 해소 밸브입니다. <code>browser</code>, <code>cron</code>, <code>message</code> 같은 무거운 기본 도구들을 쳐내, 작은 컨텍스트나 더 엄격한 OpenAI 호환 백엔드에서 프롬프트 형태가 더 작고 덜 취약해지도록 합니다.</p><p>이는 의도적으로 <strong>일반 경로가 아닙니다</strong>. 백엔드가 전체 런타임을 깔끔하게 처리한다면 이 플래그는 꺼두세요.</p><h2 id="실험적-숨겨져-있음이-아니다" tabindex="-1">실험적 = 숨겨져 있음이 아니다 <a class="header-anchor" href="#실험적-숨겨져-있음이-아니다" aria-label="Permalink to &quot;실험적 = 숨겨져 있음이 아니다&quot;">​</a></h2><p>어떤 기능이 실험적이라면 OpenClaw는 문서와 설정 경로 자체에서 그것을 명확히 표기해야 합니다. 프리뷰 동작을 안정적으로 보이는 기본 손잡이 안에 슬쩍 집어넣고 정상인 척해서는 <strong>안 됩니다</strong>. 그렇게 하면 설정 서페이스가 지저분해지기 시작합니다.</p>',11)])])}const u=t(n,[["render",d]]);export{m as __pageData,u as default};
